  if (typeof str !== 'string') return '';
  // Escape &, <, >, " and '
  return str.replace(/[&<>"']/g, function (c) {
    switch (c) {
      case '&': return '&amp;';
      case '<': return '&lt;';
      case '>': return '&gt;';
      case '"': return '&quot;';
      case "'": return '&#x27;';
    }
  });
}

